DROP TABLE IF EXISTS `boss`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `boss` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '涓婚敭ID',
  `version` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '鐗堟湰',
  `phase` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '闃舵?',
  `boss_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `hp` int unsigned NOT NULL DEFAULT '0' COMMENT '鐢熷懡鍊',
  `hp_coeff_percent` int DEFAULT NULL COMMENT '危局血量系数%（手动覆盖，空则自动计算）',
  `defense` int unsigned NOT NULL DEFAULT '0' COMMENT '闃插尽鍔',
  `level` int unsigned NOT NULL DEFAULT '1' COMMENT '绛夌骇',
  `room` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鎴块棿',
  `weakness` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '寮辩偣',
  `resistance` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鎶楁?',
  `boss_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Boss鍥剧墖',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=311512112 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Boss琛';
