DROP TABLE IF EXISTS `boss_info`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `boss_info` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `boss_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `defense` int unsigned NOT NULL DEFAULT '0',
  `level` int unsigned NOT NULL DEFAULT '1',
  `boss_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `weakness` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '弱点',
  `resistance` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '抗性',
  `crisis_base_hp` double DEFAULT NULL COMMENT '怪物危局基础血量',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_boss_name` (`boss_name`)
) ENGINE=InnoDB AUTO_INCREMENT=138 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
