INSERT INTO `buff` VALUES (14101,'1.4','1','诛心','代理人的属性异常积蓄效率提升30%，[紊乱]效果造成的伤害提升40%。\n对敌人施加[紊乱]效果时，全队回复10点能量，代理人的攻击力提升25%，持续30秒，能量回复效果20秒内最多触发一次。','/buff_image/1411.webp'),(14102,'1.4','1','速决','代理人的攻击力提升20%，喧响值获得效率提升20%；发动[终结技]时，代理人的攻击力额外提升15%，持续15秒。\n[终结技]造成的伤害提升40%，造成的失衡值提升20%，累积的属性异常积蓄值提升20%。','/buff_image/1412.webp'),(14103,'1.4','1','破招','[普通攻击]、[闪避反击]、[强化特殊技]、[冲刺攻击]造成的伤害提升30%。\n触发[极限闪避]或[极限支援]后，全队攻击力提升10%，暴击伤害提升10%，持续15秒，最多叠加3层，每层效果单独结算持续时间。','/buff_image/1413.webp'),(14201,'1.4','2','游刃','代理人的属性异常积蓄效率提升25%，异常精通提升40点。\n对敌人施加属性异常效果时，代理人额外获得500点喧响值，攻击力提升30%，持续15秒，喧响值获得效果15秒内最多触发一次。','/buff_image/1421.webp'),(14202,'1.4','2','速决','代理人的攻击力提升20%，喧响值获取效率提升20%；发动[终结技]时，代理人的攻击力额外提升15%，持续15秒。\n[终结技]造成的伤害提升40%，造成的失衡值提升20%，累积的属性异常积蓄值提升20%。','/buff_image/1422.webp'),(14203,'1.4','2','倾覆','代理人造成的失衡值提升25%，[连携技]造成的伤害提升80%。\n发动[连携技]时，代理人回复20点能量，造成的伤害提升50%，持续20秒。','/buff_image/1423.webp'),(15101,'1.5','1','异象','代理人的属性异常积蓄效率提升20%。\n对敌人施加属性异常效果时，全队提升60点异常精通，紊乱造成的伤害提升40%，持续15秒。','/buff_image/1511.webp'),(15102,'1.5','1','霜雷','代理人的电属性伤害和冰属性伤害将提升25%。\n[普通攻击]、[闪避反击]和[冲刺攻击]造成的伤害提升40%，无视敌人15%防御力。','/buff_image/1512.webp'),(15103,'1.5','1','驰援','代理人的能量获取效率提升25%，[快速支援]造成的伤害提升50%。\n每次使用[快速支援]时，全队的攻击力提升10%，持续20秒，最多可叠加3层，重复触发时刷新持续时间。','/buff_image/1513.webp'),(15201,'1.5','2','破招','[普通攻击]、[闪避反击]、[强化特殊技]、[冲刺攻击]造成的伤害提升30%。\n触发[极限闪避]或[极限支援]后，全队攻击力提升10%，暴击伤害提升10%，持续15秒，最多叠加3层，每层效果单独结算持续时间。','/buff_image/1521.webp'),(15202,'1.5','2','驰援','代理人的能量获取效率提升25%，[快速支援]造成的伤害提升50%。\n每次使用[快速支援]时，全队的攻击力提升10%，持续20秒，最多可叠加3层，重复触发时刷新持续时间。','/buff_image/1522.webp'),(15203,'1.5','2','破衡','代理人造成的失衡值提升15%，[连携技]造成的伤害提升60%。\n每次使用[连携技]时，全队的攻击力提升10%，持续20秒，最多可叠加4层，每层效果单独结算持续时间。','/buff_image/1523.webp'),(15301,'1.5','3','破衡','代理人造成的失衡值提升15%，[连携技]造成的伤害提升60%。\n每次使用[连携技]时，全队的攻击力提升10%，持续20秒，最多可叠加4层，每层效果单独结算持续时间。','/buff_image/1531.webp'),(15302,'1.5','3','灼冽','代理人的火属性异常积蓄效率和冰属性异常积蓄效率将提升20%，攻击力提升25%。\n对敌人施加属性异常效果时，代理人回复300点喧响值，提升80点异常精通，持续15秒。','/buff_image/1532.webp'),(15303,'1.5','3','终袭','代理人的喧响值获取效率提升20%。\n[终结技]造成的伤害提升30%，[终结技]命中敌人后，将使敌人的防御力降低15%，持续20秒。','/buff_image/1533.webp'),(15401,'1.5','4','驰援','代理人的能量获取效率提升25%，[快速支援]造成的伤害提升50%。\n每次使用[快速支援]时，全队的攻击力提升10%，持续20秒，最多可叠加3层，重复触发时刷新持续时间。','/buff_image/1541.webp'),(15402,'1.5','4','电火','代理人的火属性伤害和电属性伤害将提升25%。\n触发[连携技]、[极限支援]或[快速支援]后，代理人的暴击率提升20%，暴击伤害提升40%，持续20秒。','/buff_image/1542.webp'),(15403,'1.5','4','积异','代理人的异常积蓄效率提升10%，拥有护盾时异常积蓄效率额外提升20%。\n攻击处于属性异常状态中的敌人时，代理人造成的伤害提升40%。','/buff_image/1543.webp'),(16101,'1.6','1','游刃','代理人的属性异常积蓄效率提升25%，异常精通提升40点。\n对敌人施加属性异常效果时，代理人额外获得500点喧响值，攻击力提升30%，持续15秒，喧响值获得效果15秒内最多触发一次。','/buff_image/1611.webp'),(16102,'1.6','1','驰援','代理人的能量获取效率提升25%，[快速支援]造成的伤害提升50%。\n每次使用[快速支援]时，全队的攻击力提升10%，持续20秒，最多可叠加3层，重复触发时刷新持续时间。','/buff_image/1612.webp'),(16103,'1.6','1','锐进','代理人的[追加攻击]、[连携技]造成的伤害提升30%。\n[追加攻击]、[闪避反击]命中敌人时，全队的攻击力提升15%，暴击伤害提升40%，持续20秒，重复触发时刷新持续时间。','/buff_image/1613.webp'),(16201,'1.6','2','锐进','代理人的[追加攻击]、[连携技]造成的伤害提升30%。\n[追加攻击]、[闪避反击]命中敌人时，全队的攻击力提升15%，暴击伤害提升40%，持续20秒，重复触发时刷新持续时间。','/buff_image/1621.webp'),(16202,'1.6','2','昏惫','代理人造成的失衡值提升10%，连携技造成的伤害提升50%。\n[连携技]命中敌人时，敌人的失衡易伤倍率提升25%，且全队攻击力提升20%，持续15秒，重复触发时刷新持续时间。','/buff_image/1622.webp'),(16203,'1.6','2','灼冽','代理人的火属性异常积蓄效率和冰属性异常积蓄效率将提升20%，攻击力提升25%。\n对敌人施加属性异常效果时，代理人回复400点喧响值，提升80点异常精通，持续15秒。','/buff_image/1623.webp'),(16301,'1.6','3','终袭','代理人的喧响值获取效率提升20%。\n[终结技]造成的伤害提升30%，[终结技]命中敌人后，将使敌人的防御力降低15%，持续20秒。','/buff_image/1631.webp'),(16302,'1.6','3','昏惫','代理人造成的失衡值提升10%，连携技造成的伤害提升50%。\n[连携技]命中敌人时，敌人的失衡易伤倍率提升25%，且全队攻击力提升20%，持续15秒，重复触发时刷新持续时间。','/buff_image/1632.webp'),(16303,'1.6','3','激变','代理人的火属性异常积蓄效率和以太属性异常积蓄效率将提升20%，异常精通提升80。\n触发属性异常时，敌人的防御力降低15%，且承受的属性异常伤害提升40%，持续15秒，重复触发时刷新持续时间。','/buff_image/1633.webp'),(17101,'1.7','1','驰援','代理人的能量获取效率提升25%，[快速支援]造成的伤害提升50%。\n每次使用[快速支援]时，全队的攻击力提升10%，持续20秒，最多可叠加3层，重复触发时刷新持续时间。','/buff_image/1711.webp'),(17102,'1.7','1','锐进','代理人的[追加攻击]、[连携技]造成的伤害提升30%。\n[追加攻击]、[闪避反击]命中敌人时，全队的攻击力提升15%，暴击伤害提升40%，持续20秒，重复触发时刷新持续时间。','/buff_image/1712.webp'),(17103,'1.7','1','蓄变','代理人的以太属性异常积蓄效率和物理属性异常积蓄效率将提升25%，异常精通提升60点。\n触发属性异常时，敌人的防御力降低10%，且承受的属性异常伤害提升30%，持续20秒，重复触发时刷新持续时间。','/buff_image/1713.webp'),(17201,'1.7','2','游刃','代理人的属性异常积蓄效率提升25%，异常精通提升40点。\n对敌人施加属性异常效果时，代理人额外获得500点喧响值，攻击力提升30%，持续15秒，喧响值获得效果15秒内最多触发一次。','/buff_image/1721.webp'),(17202,'1.7','2','昏惫','代理人造成的失衡值提升10%，连携技造成的伤害提升50%。\n[连携技]命中敌人时，敌人的失衡易伤倍率提升25%，且全队攻击力提升20%，持续15秒，重复触发时刷新持续时间。','/buff_image/1722.webp'),(17203,'1.7','2','狂岚','代理人的[特殊技]、[强化特殊技]、[终结技]造成的伤害提升30%。\n[强化特殊技]、[追加攻击]命中敌人时，代理人的暴击伤害提升30%，持续20秒，并使敌人的防御力降低15%，持续15秒，重复触发时刷新持续时间。','/buff_image/1723.webp'),(17301,'1.7','3','异象','代理人的属性异常积蓄效率提升20%。\n对敌人施加属性异常效果时，全队提升60点异常精通，紊乱造成的伤害提升40%，持续15秒。','/buff_image/1731.webp'),(17302,'1.7','3','崩倾','代理人的[闪避反击]、[强化特殊技]造成的伤害提升30%。\n代理人命中非失衡状态敌人时，造成的失衡值提升10%；命中失衡状态中的敌人时，暴击伤害提升30%，敌人的失衡易伤倍率提升25%。','/buff_image/1732.webp'),(17303,'1.7','3','奏鸣','代理人的喧响值获取效率提升20%。\n[终结技]和[强化特殊技]命中敌人时，无视其20%的伤害抗性，[终结技]命中敌人后，代理人的[终结技]和[强化特殊技]造成的伤害提升50%，持续30秒，重复触发时刷新持续时间。','/buff_image/1733.webp'),(20101,'2.0','1','破招','[普通攻击]、[闪避反击]、[强化特殊技]、[冲刺攻击]造成的伤害提升30%。\n触发[极限闪避]或[极限支援]后，全队攻击力提升10%，暴击伤害提升10%，持续15秒，最多叠加3层，每层效果单独结算持续时间。','/buff_image/2011.webp'),(20102,'2.0','1','蓄变','代理人的以太属性异常积蓄效率和物理属性异常积蓄效率将提升25%，异常精通提升60点。\n触发属性异常时，敌人的防御力降低10%，且承受的属性异常伤害提升30%，持续20秒，重复触发时刷新持续时间。','/buff_image/2012.webp'),(20103,'2.0','1','凝神','代理人的生命值上限提升30%，终结技造成的伤害提升40%。\n代理人释放终结技后，能量和闪能获得效率 提升15%，以太属性伤害和冰属性伤害提升40%，持续20秒。','/buff_image/2013.webp'),(20201,'2.0','2','游刃','代理人的属性异常积蓄效率提升25%，异常精通提升40点。\n对敌人施加属性异常效果时，代理人额外获得500点喧响值，攻击力提升30%，持续15秒，喧响值获得效果15秒内最多触发一次。','/buff_image/2021.webp'),(20202,'2.0','2','奏鸣','代理人的喧响值获取效率提升20%。\n[终结技]和[强化特殊技]命中敌人时，无视其20%的伤害抗性，[终结技]命中敌人后，代理人的[终结技]和[强化特殊技]造成的伤害提升50%，持续30秒，重复触发时刷新持续时间。','/buff_image/2022.webp'),(20203,'2.0','2','沉疴','使敌人进入失衡状态后，其失衡易伤倍率提升25%，失衡恢复速度降低10%。\n代理人释放连携技后，自身的攻击力提升20%，暴击伤害提升30%，持续20秒。','/buff_image/2023.webp'),(20301,'2.0','3','驰援','代理人的能量获取效率提升25%，[快速支援]造成的伤害提升50%。\n每次使用[快速支援]时，全队的攻击力提升10%，持续20秒，最多可叠加3层，重复触发时刷新持续时间。','/buff_image/2031.webp'),(20302,'2.0','3','凝神','代理人的生命值上限提升30%，终结技造成的伤害提升40%。\n代理人释放终结技后，能量和闪能获得效率 