/*!40000 ALTER TABLE `changelog` DISABLE KEYS */;
INSERT INTO `changelog` VALUES (45,'3.0.0','云服务器首发上线','将 ZZZ-HP 完整站点部署至阿里云，面向公网访问。\n\n主要包含：\n· 危局强袭战：期数查询、血量与膨胀折线、对比等\n· 式舆防卫战：新旧防卫数据浏览与管理\n· 临界推演：相关模式入口与数据\n· 角色计算器：队伍编组、音擎 / 驱动盘 / 邦布选择，局外面板与伤害乘区计算\n· 管理后台：Boss / Buff / 计算器增益等数据维护\n· 数据库与图片资源（boss / buff / calculator）同步上线','2026-07-13 12:00:00','2026-07-24 16:30:04','2026-07-24 16:30:04'),(46,'3.0.1','角色计算器识别与词条计算','相对 3.0.0 云上版本的增量更新：\n\n· 面板截图 OCR：支持云识别与本地兜底，一键填入主 C 配置与局外面板\n· 词条计算：由识别出的局外面板按公式反推副词条条数\n· 识别 4 / 5 / 6 号盘主属性，写入词条计算并在反推时扣除主属性贡献\n· 侧栏「计算方式」下可切换面板计算 / 词条计算，与页内 Tab 同步\n· 计算器交互与白天主题样式优化（图片录入分区、选择器对齐等）\n· 首页新增更新日志；管理后台可新增、编辑、删除更新日志','2026-07-14 15:00:00','2026-07-24 16:30:04','2026-07-24 16:30:04'),(47,'3.0.2','手机端适配与白天主题修正','相对 3.0.1 的增量更新（以手机端适配为主，电脑端观感基本不变）：\n\n· 危局强袭战手机端：侧栏改为抽屉菜单；往期详细竖排展示，支持上一期 / 选期 / 下一期\n· 折线图手机端：工具栏换行、短提示文案；总览点开详细弹窗可滚动查看\n· 期数对比、Buff 对比、Buff 总览、怪物对比改为整页滚动，修复页面卡住无法滚动\n· 式舆防卫战同步完成上述手机端适配（往期详细、折线图点开详细等）\n· 角色计算器手机端：侧栏抽屉、组队槽位与选择网格收紧，面板录入字段单列\n· 计算器白天主题补全：队伍摘要、代理人槽位音擎 / 驱动盘框、影画与精炼拖动条、驱动盘编辑条等不再残留深色样式','2026-07-16 09:00:00','2026-07-24 16:30:04','2026-07-24 16:30:04'),(48,'3.0.3','留言板与网站说明','相对 3.0.2 的增量更新（留言板与社区功能为主）：\n\n· 留言板（委托）：发布 / 浏览委托，分类筛选、搜索、评论、点赞、收藏；帖子按活跃时间排序，未读标题高亮\n· 留言板瀑布流列表：横向优先排布，封面高度随图片比例自适应，列内紧凑堆叠\n· 个人名片：头像 / 横幅、发帖 / 粉丝 / 关注、置顶与社交展示；支持查看他人名片\n· 敲敲：系统通知、关注动态、私信聊天；关注会话按发布者头像与昵称展示\n· @ 提及：评论可 @ 用户（头像 + 昵称 + UID），并支持发送图片与基础表情\n· 米游社扫码登录与多账号切换；留言板管理员与全站推送（公告 / 更新日志）\n· 首页新增「网站说明」独立页面；管理后台可编辑说明文案；借鉴与参考含可点击外链\n· 站点 favicon 更换为 ZZZ-HP 图标','2026-07-20 22:00:00','2026-07-24 16:30:04','2026-07-24 16:30:04'),(49,'3.0.4','最优词条分配与留言板管理','相对 3.0.3 的增量更新（角色计算器最优词条分配与留言板管理优化为主）：\n\n· 角色计算器新增「最优词条分配」：在约束下扫掠局外大攻击/大生命与爆伤或精通的分配，绘制直伤或异常/紊乱/乱流期望伤害柱状图\n· 点击柱体可查看计算过程、副词条差异、收益曲线；异常模式三张图悬停联动；最高柱体标记与期望伤害提示\n· 支持额外 Buff、局外/局内面板与局内增益汇总；主词条差异支持单槽位替换与 4/5/6 号盘综合对比\n· 调整 4/5/6 号盘主属性或切换计算方式时保留当前输入与选中状态；调整小词条时保持已选柱体分配\n· 副词条差异表新增「当前词条数」；选中分配展示攻击力/生命值与穿透值词条\n· 留言板管理整合账号管理（委托 / 账号分区）；封禁账号登录与接口返回明确封禁提示','2026-07-21 16:30:00','2026-07-24 16:30:04','2026-07-24 16:30:04'),(50,'3.0.5','留言板匿名与敏感内容','相对 3.0.4 的增量更新（留言板匿名与敏感内容为主）：\n\n· 委托与评论支持匿名发布：仅隐藏账号信息，仍归属发布账号；作者编辑时可随时开启或取消匿名\n· 名片新增「匿名委托」分区；「我的评论」中匿名评论带标注；他人名片默认不展示匿名委托\n· 敏感内容标记：封面与图片模糊处理、点击可查看，模糊仅作用于图片本身不遮挡头像\n· 管理区新增「敏感内容」分区，并提供「屏蔽所有敏感内容」全局开关（不改变帖子屏蔽状态）\n· 管理员可查看匿名委托 / 评论作者的真实头像、昵称与 UID，并可进入其名片\n· 粉丝 / 关注星标优化：被标记用户置顶展示；匿名 / 敏感开关样式调整为高亮配色','2026-07-21 18:00:00','2026-07-24 16:30:04','2026-07-24 16:30:04'),(51,'3.0.6','留言板等级、收藏表情与互动','相对 3.0.5 的增量更新（留言板等级、表情收藏与互动体验为主）：\n\n· 账号等级与经验：打卡、发帖、评论、点赞 / 被点赞等行为获取经验，受每日上限约束；留言板头部展示头像与经验槽\n· 收藏表情：双击图片 / 表情打开查看器，可缩放拖动、下载；右上角爱心收藏；面板显示容量（如 4/48）并支持删除确认\n· 发送表情或选用收藏表情后自动收起选择框；相关提示短时显示后自动消失\n· 评论点赞：评论底部可点赞；帖子与评论统一为简约点赞图标，数量与图标之间用细线分隔\n· 举报：委托与评论可举报并附原因；管理员在管理区「举报」分区处理，敲敲同步通知\n· 评论 / 聊天操作菜单：引用、拉黑、屏蔽、删除等对齐绳网风格；更多菜单改为浮层定位，避免被列表裁切\n· 游客仅可浏览，发帖与评论需登录；敲敲搜索与聊天互斥，返回时恢复上次状态','2026-07-22 18:30:00','2026-07-24 16:30:04','2026-07-24 16:30:04'),(52,'3.0.7','举报封禁流程与计算器预设输入','相对 3.0.6 的增量更新（举报 / 封禁流程与角色计算器输入为主）：\n\n· 举报完善：同一帖 / 评论 / 用户每天可各举报一次；名片可举报用户；敲敲未读红点；管理员通知含「前往处理」\n· 用户举报仅通知站点管理员；处理反馈可附自定义说明；举报相关通知不再泄露内部 token\n· 管理区举报分区：帖子 / 评论 / 用户，以及已处理 / 未处理；跳转定位并高亮被举报内容\n· 封禁调整：可登录但禁发帖 / 评论，敲敲仍可用；支持 1 / 3 / 7 / 30 天或永久，并写明原因通知本人\n· 头像经验槽与名片显示「封禁状态」；可查看原因 / 起止与剩余时长，并申请解封（通知站点管理员）\n· 封禁时长选择与确认 / 解封弹窗样式对齐留言板\n· 伤害计算：有效防御展开折后防御完整算式后再减穿透值\n· 敌方防御 / 失衡易伤：预设合框（可手输）；防御默认 953（477 / 953 / 1588），失衡易伤 1 / 1.25 / 1.5 / 1.8 / 2.1；暗夜 / 白天主题均可读\n· 最优词条：4 / 5 / 6 号盘同类主词条出现 x 次时，对应副词条上限为 36 - 6x（暴击约束暴击）','2026-07-22 23:00:00','2026-07-24 16:30:04','2026-07-24 16:30:04'),(53,'3.0.8','危局折线图与留言板手机端体验','相对 3.0.7 的增量更新（危局折线图体验、分数血量表与留言板手机端为主）：\n\n· 危局新增「分数与血量对应表」；血量折线图可叠加均 1.5w / 均 2w（FS-HP）或困难星级线，并单独绘制对应相对膨胀图\n· 折线图小窗改为各折线当前数值，并按数值从高到低排列；顶栏勾选显示哪些折线图（取消收齐）；单图加高约两张占满一屏\n· 相对膨胀折线颜色与血量图对应折线一致；1.0 基准虚线同色；默认不显示均 1.5w / 均 2w 相对膨胀（可勾选打开）\n· 图例更名：总血量、均 1.5w 分血量、均 2w 分血量（FS-HP）；血量折线图侧栏标题白天黑字 / 暗夜白字\n· 怪物对比：血量系数与血量系数增长紧挨排列；往期详细标注危局血量系数相对上期实际增减\n· 期数对比去外框、布局与血量图一致；进入危局 / 防卫默认选中最新已公开期数\n· 最优词条：收益曲线悬停与下一条提升按收益从高到低；「收益曲线」与「计算过程」按键位置对调\n· 留言板手机端：筛选 / 搜索 / 分类随列表滚动；详情正文与评论分 Tab；多图可点按 / 滑动查看\n· 顶部交叉网格改回纯黑顶栏；手机端头部用户信息与按钮换行防重叠\n· 敲敲：未读可跳转到系统 / 关注 / 聊天对应分区；全部已读即时清除外侧红点；私信加载最近消息并滚到底部\n· 点击未读通知跳转帖子 / 评论并用引用同款高亮提示','2026-07-23 21:30:00','2026-07-24 16:30:04','2026-07-24 16:30:04'),(54,'3.0.9','计算器增益效果块与小数数值','相对 3.0.8 的增量更新（角色计算器增益体系重构为主）：\n\n· 增益改为效果块结构：一块可含多条效果，前台按块勾选；展示以效果块名称与块备注为准\n· 删除「增益产生方」与效果级备注编辑 / 展示，避免与效果块信息重复\n· 增益数值支持小数输入与步进；转模默认基础值 / 上限等同步支持小数\n· 新增增益「作用情况」：全局 / 失衡期 / 非失衡期，结算与自定义额外 Buff 按失衡阶段过滤\n· 换角色 / 音擎 / 驱动盘等配置时重置 Buff 勾选与层数，避免串用旧勾选\n· 异职音擎：职业不匹配时不结算音擎增益（任一方职业为空仍兼容放行）\n· 「额外 Buff 增益」与 Buff 选择弹窗补全白天主题；站点 favicon 恢复为 ZZZ-HP 标识','2026-07-25 00:20:00','2026-07-24 16:30:04','2026-07-24 16:30:04');
/*!40000 ALTER TABLE `changelog` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `character`
--

DROP TABLE IF EXISTS `character`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `character` (
  `id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '角色ID',
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '角色名称',
  `profession` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '职业',
  `element` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '属性',
  `support_needs` json NOT NULL COMMENT '辅助需求属性数组',
  `avatar_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '头像路径',
  `note` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '注释',
  `base_panel` json NOT NULL,
  `mindscape_notes` json NOT NULL COMMENT '0-6影画注释数组',
  `mindscape_buffs` json NOT NULL COMMENT '0-6影画增益数组',
  `raw_json` json NOT NULL COMMENT '原始完整文档，防丢字段',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='角色增益表';
/*!40101 SET character_set_client = @saved_cs_client */;

