DROP TABLE IF EXISTS `guestbook`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `guestbook` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `nickname` varchar(40) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '匿名',
  `user_id` int unsigned DEFAULT NULL COMMENT '登录用户ID',
  `title` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '标题',
  `category` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '灌水' COMMENT '分类',
  `content` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '正文',
  `cover` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '封面图',
  `images_json` text COLLATE utf8mb4_unicode_ci COMMENT '图片列表JSON',
  `is_hidden` tinyint(1) NOT NULL DEFAULT '0',
  `is_anonymous` tinyint(1) NOT NULL DEFAULT '0' COMMENT '匿名发布',
  `is_pinned` tinyint(1) NOT NULL DEFAULT '0' COMMENT '全局置顶',
  `pinned_at` timestamp NULL DEFAULT NULL COMMENT '置顶时间',
  `profile_pinned` tinyint(1) NOT NULL DEFAULT '0' COMMENT '个人主页置顶',
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '软删除',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `view_count` int unsigned NOT NULL DEFAULT '0' COMMENT '浏览量',
  `moderation_message` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '管理员屏蔽/删除留言',
  `restore_requested_at` timestamp NULL DEFAULT NULL COMMENT '用户申请恢复时间',
  `is_sensitive` tinyint(1) NOT NULL DEFAULT '0' COMMENT '敏感内容（图片默认模糊）',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_guestbook_visible_created` (`is_hidden`,`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

