CREATE TABLE `site_info_section` (
  `panel_key` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '栏目键 about/features/credits/legal',
  `title` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '栏目标题',
  `content` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '栏目正文（纯文本）',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`panel_key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='网站说明栏目';
