LOCK TABLES `site_info_section` WRITE;
/*!40000 ALTER TABLE `site_info_section` DISABLE KEYS */;
INSERT INTO `site_info_section` VALUES ('about','关于本站','ZZZ-HP 是由粉丝制作的《绝区零》非官方工具站，旨在整理玩法数据、提供计算辅助，并搭建玩家交流空间。\n\n本站与 HoYoverse / 米哈游官方无任何隶属或授权关系，所有功能由爱好者社区维护，仅供交流与学习使用。','2026-07-20 14:23:57'),('credits','借鉴与参考','【InterKnot】\nhttps://interk.net/\n留言板与「敲敲」通知 / 聊天交互、弹层与卡片布局、个人名片展示、@ 提及样式及部分线框图标交互。\n\n很成熟的绳网论坛，功能较为完善，整体也很活跃，留言板的格式不少是参考的InterKnot，大家感兴趣的可以去看看。\n\n【ZZZ Calculator】\nhttps://zzzcaculator.top/\n最优词条计算的展示项参考其中词条分析，后续buff的展示可能也会参考，目前ZZZ-HP的角色增益等太过死板，很多还是依赖人工调节，后蓄会优化。\n\n最近出世的背包最优驱动盘计算器，会扫描导入背包中的驱动盘，并且支持配对+不同buff下的最优驱动盘计算，会给出哪一套驱动盘是最适合的；唯一可惜的就是目前支持的角色还是太少，毕竟还是刚起步。\n\n【米游社】\n账号登录（扫码登录、可选手机号登录）。\n\n【nanoka】\nhttps://zzz.nanoka.cc/\n式舆防卫战等部分历史数据在维护时参考了该站的公开社区数据，仅供本站展示与对比使用。','2026-07-21 08:39:21'),('features','网站内容','【危局强袭战】\n往期详细查询（含手机端上一期 / 选期 / 下一期）、总血量折线图、期数对比折线图、单独怪物对比、Buff 总览与 Buff 对比。\n\n【式舆防卫战】\n新旧防卫战数据浏览；与危局强袭战相同的往期详细、折线图与对比能力；历史数据整理与对照。\n\n【临界推演】\n相关模式入口与数据浏览。\n\n【角色计算器】\n· 队伍编组、音擎 / 驱动盘 / 邦布选择，局外面板与伤害乘区计算\n· 图片录入：面板截图 OCR（云识别 + 本地兜底），识别 4 / 5 / 6 号盘主属性并一键填入\n· 计算方式：面板计算、词条计算（由局外面板反推副词条）、最优词条分配（扫掠分配并绘制期望伤害柱状图 / 收益曲线）\n· 支持额外 Buff、局外 / 局内面板与增益汇总；白天 / 夜间主题与手机端适配\n\n【留言板（委托）】\n· 发布 / 浏览委托：分类筛选、搜索、瀑布流列表、评论、点赞、收藏；支持图文与表情、@ 提及\n· 匿名发布：委托与评论可隐藏账号信息，仍归属本人，可随时取消匿名；名片有「匿名委托」分区\n· 敏感内容：封面与图片可模糊遮罩、点击查看；管理区可筛选敏感帖，并可全局屏蔽前台敏感委托\n· 个人名片：头像 / 横幅、我的委托 / 评论 / 收藏、粉丝与关注（星标置顶）、查看他人名片\n· 敲敲：系统通知、关注动态、私信聊天；米游社扫码登录与多账号切换\n\n【首页与说明】\n更新日志展示；「网站说明」独立页面（关于本站 / 网站内容 / 借鉴与参考 / 版权声明）。\n\n【管理后台】\nBoss / Buff / 计算器等数据维护；更新日志与网站说明编辑；留言板委托与账号管理（屏蔽、删除、封禁、敏感内容与匿名身份查看）等。','2026-07-21 10:21:56'),('legal','版权声明','ZZZ-HP 是粉丝制作的网站。\n\n游戏中相关的图像、角色、名称、UI 元素及其他资产的版权与商标权均归 HoYoverse 所有。\n\n本站不对游戏内数据的准确性作官方保证，亦不代表任何官方立场。','2026-07-20 14:23:57');
/*!40000 ALTER TABLE `site_info_section` ENABLE KEYS */;
UNLOCK TABLES;

