  `profession` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '职业',
  `rarity` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'A' COMMENT '稀有度 S/A/B',
  `avatar_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '头像路径',
  `note` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '音擎注释',
  `base_atk` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '基础攻击力',
  `advanced_stats` json NOT NULL,
  `fixed_buffs` json NOT NULL COMMENT '固定自身/队友增益',
  `refinement_buffs` json NOT NULL COMMENT '精炼1-5增益数组',
  `raw_json` json NOT NULL COMMENT '原始完整文档，防丢字段',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='音擎增益表';
